@echo off
REM Pico-ResQ 避難所管理システム セットアップスクリプト (Windows用)

setlocal enabledelayedexpansion

REM スクリプトはscripts/ディレクトリから実行されるため、プロジェクトルートに移動
cd /d "%~dp0\.."

echo.
echo ============================================================
echo Pico-ResQ 避難所管理システム セットアップ
echo ============================================================
echo.

REM Pythonのバージョンチェック（仮想環境を避けるため py を優先）
echo [情報] Pythonのバージョンを確認中...
set "PY_CMD="
set "PY_ARGS="
where py >nul 2>&1
if not errorlevel 1 (
    set "PY_CMD=py"
    set "PY_ARGS=-3"
) else (
    where python >nul 2>&1
    if not errorlevel 1 (
        set "PY_CMD=python"
    )
)

if "!PY_CMD!"=="" (
    echo [エラー] Pythonがインストールされていません。
    echo Python 3.11以上をインストールしてください: https://www.python.org/
    exit /b 1
)

for /f "tokens=2" %%i in ('!PY_CMD! !PY_ARGS! --version 2^>^&1') do set PYTHON_VERSION=%%i
if "!PYTHON_VERSION!"=="" (
    echo [エラー] Pythonのバージョン取得に失敗しました。
    exit /b 1
)

for /f "tokens=1,2 delims=." %%a in ("!PYTHON_VERSION!") do (
    set "PY_MAJOR=%%a"
    set "PY_MINOR=%%b"
)

if "!PY_MAJOR!"=="" (
    echo [エラー] Pythonのバージョン取得に失敗しました。
    exit /b 1
)

if !PY_MAJOR! LSS 3 (
    echo [エラー] Python 3.11以上が必要です。現在: !PYTHON_VERSION!
    exit /b 1
) else (
    if !PY_MAJOR! EQU 3 (
        if !PY_MINOR! LSS 11 (
            echo [エラー] Python 3.11以上が必要です。現在: !PYTHON_VERSION!
            exit /b 1
        )
    )
)

echo [成功] Python !PYTHON_VERSION! を確認しました。

REM Node.jsのチェック
echo [情報] Node.jsのインストールを確認中...
node --version >nul 2>&1
if errorlevel 1 (
    echo [警告] Node.jsがインストールされていません。
    echo [警告] Node.js LTS版をインストールしてください: https://nodejs.org/
    set SKIP_FRONTEND=true
) else (
    for /f %%i in ('node --version') do set NODE_VERSION=%%i
    echo [成功] Node.js !NODE_VERSION! を確認しました。
    set SKIP_FRONTEND=false
)

REM バックエンドのセットアップ
echo.
echo ============================================================
echo バックエンド (Python) のセットアップ
echo ============================================================
echo.

if not exist "backend\requirements.txt" (
    echo [エラー] requirements.txt が見つかりません: backend\requirements.txt
    exit /b 1
)

echo [情報] pipの確認中...
!PY_CMD! !PY_ARGS! -m pip --version >nul 2>&1
if errorlevel 1 (
    echo [警告] pipが見つからないため、ensurepipを実行します...
    !PY_CMD! !PY_ARGS! -m ensurepip --upgrade
    if errorlevel 1 (
        echo [エラー] pipのセットアップに失敗しました。
        cd ..
        exit /b 1
    )
)

echo [情報] 依存関係をインストール中... (ユーザー領域)
cd backend
!PY_CMD! !PY_ARGS! -m pip install --user -r requirements.txt
if errorlevel 1 (
    echo [エラー] 依存関係のインストールに失敗しました。
    cd ..
    exit /b 1
)
cd ..
echo [成功] バックエンドの依存関係のインストールが完了しました。

REM フロントエンドのセットアップ
if "!SKIP_FRONTEND!"=="false" (
    echo.
    echo ============================================================
    echo フロントエンド (Electron) のセットアップ
    echo ============================================================
    echo.

    if not exist "electron\package.json" (
        echo [エラー] package.json が見つかりません: electron\package.json
        exit /b 1
    )

    echo [情報] 依存関係をインストール中...
    cd electron
    call npm install
    if errorlevel 1 (
        echo [エラー] 依存関係のインストールに失敗しました。
        cd ..
        exit /b 1
    )
    cd ..
    echo [成功] フロントエンドの依存関係のインストールが完了しました。
) else (
    echo [警告] フロントエンドのセットアップをスキップしました。
)

REM 完了メッセージ
echo.
echo ============================================================
echo セットアップ完了
echo ============================================================
echo.
echo [成功] すべてのセットアップが完了しました！
echo.
echo 次のステップ:
echo 1. バックエンドを起動: cd backend ^&^& !PY_CMD! !PY_ARGS! -m uvicorn main:app --reload --host 0.0.0.0 --port 8000
echo 2. フロントエンドを起動: cd electron ^&^& npm start
echo.
echo 詳細は README.md を参照してください。
echo.

pause
